import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Careers = () => {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedJob, setSelectedJob] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);

  useEffect(() => {
    const fetchJobs = async () => {
      try {
        const res = await axios.get('http://localhost:5001/api/jobs');
        setJobs(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Backend failed", err);
        setLoading(false);
      }
    };
    fetchJobs();
  }, []);

  return (
    <div className="bg-white font-sans min-h-screen">
      {/* SECTION HEADER */}
      <section className="pt-32 pb-12 px-6 max-w-7xl mx-auto">
        <h2 className="text-5xl font-black text-gray-950 tracking-tighter">Open Positions</h2>
      </section>

      {/* JOBS LISTING */}
      <section className="pb-24 px-6 max-w-7xl mx-auto">
        <div className="grid gap-px bg-gray-100 border-y border-gray-100">
          {loading ? (
            <div className="bg-white py-20 text-center">
               <p className="text-gray-400 font-medium tracking-widest animate-pulse">Loading opportunities...</p>
            </div>
          ) : jobs.length > 0 ? (
            jobs.map((job) => (
              <div key={job._id} className="group grid grid-cols-1 md:grid-cols-12 items-center p-8 md:p-10 bg-white hover:bg-gray-50 transition-all duration-300">

                {/* Column 1: Job Title (Not Bold) */}
                <div className="md:col-span-5">
                  <h3 className="text-2xl text-gray-800 font-medium tracking-tight group-hover:text-orange-600 transition-colors">
                    {job.title}
                  </h3>
                </div>

                {/* Column 2: Location & Salary (Bagal me, halka distance) */}
                <div className="md:col-span-4 mt-2 md:mt-0">
                  <div className="flex items-center gap-8"> {/* gap-8 controls the distance */}
                    <p className="text-gray-500 font-medium text-sm flex items-center gap-1">
                      <span className="text-gray-300">📍</span> {job.loc}
                    </p>
                    <p className="text-gray-400 font-medium text-sm border-l border-gray-200 pl-8">
                      {job.salary}
                    </p>
                  </div>
                </div>

                {/* Column 3: Apply Button */}
                <div className="md:col-span-3 mt-6 md:mt-0 text-right">
                  <button 
                    onClick={() => { setSelectedJob(job); setIsFormOpen(true); }}
                    className="w-full md:w-auto bg-gray-950 text-white px-10 py-3.5 rounded-full font-bold text-sm hover:bg-orange-600 hover:shadow-lg transition-all"
                  >
                    Apply Now
                  </button>
                </div>

              </div>
            ))
          ) : (
            <div className="bg-white py-20 text-center">
              <p className="text-gray-400 font-medium">No positions found.</p>
            </div>
          )}
        </div>
      </section>

      {/* Modal logic stays the same */}
    </div>
  );
};

export default Careers;
